(function () {
  const d = document;

  const p1 = [115,101,100];  
  const p2 = [99,111,110];   
  const p3 = [116,97,99,116];   
  const p4 = [105,46];      
  const p5 = [117,107];       
  const p6 = [64];       

  function build() {
    const arr = [
      ...p2, ...p3,
      ...p6, 
      ...p1, ...p4, 
      ...p5      
    ];

    const email = String.fromCharCode.apply(null, arr);

    const a = d.createElement('a');
    a.href = 'mailto:' + email;
    a.textContent = email;

    const el = d.getElementById('e');
    if (el) el.appendChild(a);
  }

  let done = false;

  function trigger() {
    if (done) return;
    done = true;
    setTimeout(build, 200 + Math.random() * 300);
  }

  window.addEventListener('load', trigger);
  window.addEventListener('mousemove', trigger);
  window.addEventListener('scroll', trigger);
})();
